import { invoke } from "@tauri-apps/api/core";

import { toConnectionDto } from "./dto";
import type { ChatMessage, ConnectionConfig } from "./types";

/** Non-streamed completion — used for the "test connection" button in M1.
 * Full streaming (`chatStream`) lands in M2. */
export async function chatComplete(
  connection: ConnectionConfig,
  messages: ChatMessage[],
): Promise<string> {
  return invoke<string>("chat_complete", {
    connection: toConnectionDto(connection),
    messages,
  });
}

import type { ChatMessage, ConnectionConfig } from "./types";

/** Rust's `ConnectionDto` deserializes with plain (snake_case) field names —
 * unlike the camelCase `ConnectionConfig` used in the rest of the app. */
export interface ConnectionDto {
  id: string;
  provider: string;
  base_url: string | null;
  model: string;
  temperature: number;
  top_p: number;
  top_k?: number;
  min_p?: number;
  frequency_penalty?: number;
  presence_penalty?: number;
  max_tokens: number;
}

export function toConnectionDto(config: ConnectionConfig): ConnectionDto {
  const dto: ConnectionDto = {
    id: config.id,
    provider: config.provider,
    base_url: config.baseUrl,
    model: config.model,
    temperature: config.temperature,
    top_p: config.topP,
    max_tokens: config.maxTokens,
  };
  if (config.topK !== undefined) dto.top_k = config.topK;
  if (config.minP !== undefined) dto.min_p = config.minP;
  if (config.frequencyPenalty !== undefined) dto.frequency_penalty = config.frequencyPenalty;
  if (config.presencePenalty !== undefined) dto.presence_penalty = config.presencePenalty;
  return dto;
}

export type ChatMessageDto = ChatMessage;

export type Provider = "openai" | "gemini" | "claude";

export type ConnectionPurpose = "chat" | "image" | "embedding";

/** EXPERIMENTAL (function-calling prototype, see `src/chat/toolCalling.ts`):
 * one prior `functionCall` the model made, replayed in a following request
 * as an `assistant`-role turn's `function_call` field. */
export interface ChatFunctionCall {
  name: string;
  args: unknown;
  /** Gemini's opaque per-call token — must be replayed verbatim on the
   * follow-up request or the API rejects it with HTTP 400. */
  thoughtSignature?: string;
}

/** EXPERIMENTAL: the app's answer to a prior `ChatFunctionCall`, sent back
 * as a `user`-role turn's `function_response` field so the model can resume
 * generation with the looked-up detail in context. */
export interface ChatFunctionResponse {
  name: string;
  response: unknown;
}

export interface ChatMessage {
  role: "system" | "user" | "assistant";
  content: string;
  /** EXPERIMENTAL: present only on the assistant turn that represents the
   * model's own prior tool call — `content` is normally empty then. */
  function_call?: ChatFunctionCall;
  /** EXPERIMENTAL: present only on the user turn that carries the app's
   * tool result back to the model — `content` is normally empty then. */
  function_response?: ChatFunctionResponse;
}

/** Mirrors the `connections` table row. The API key never lives here — it
 * stays in the secrets file and is looked up by `id` on the Rust side. */
export interface ConnectionConfig {
  id: string;
  name: string;
  provider: Provider;
  purposes: ConnectionPurpose[];
  baseUrl: string | null;
  model: string;
  temperature: number;
  topP: number;
  topK?: number;
  minP?: number;
  frequencyPenalty?: number;
  presencePenalty?: number;
  maxTokens: number;
  contextBudget: number;
  createdAt: string;
  updatedAt: string;
}

export type ConnectionDraft = Omit<ConnectionConfig, "id" | "createdAt" | "updatedAt">;

export interface ChatParams {
  temperature: number;
  topP: number;
  maxTokens: number;
}

/** Streaming events emitted by the future `chat_stream` command (M2). Kept
 * here now so the shape is settled ahead of time. */
export type StreamEvent =
  | { event: "Start" }
  | { event: "Token"; data: { text: string } }
  /** EXPERIMENTAL (function-calling prototype, Gemini only): terminal for
   * the current `chat_stream` call, same as `Done`/`Error` — the model
   * paused generation to invoke a tool. The caller must execute the tool,
   * append a function-call + function-response message pair, and issue a
   * fresh `chat_stream` call (with `tools: true`) to resume generation. */
  | { event: "FunctionCall"; data: { name: string; args: unknown; thoughtSignature?: string } }
  | { event: "Done"; data: { finish_reason: string } }
  | { event: "Error"; data: { message: string; retryable: boolean } };

// Error log collection (roadmap M11 §3, tiered logging follow-up): wraps
// console.debug/info/warn/error and catches uncaught window errors /
// unhandled promise rejections, forwarding each one to the Rust
// `append_log` command so it lands in `$APPDATA/logs/app.log`. Users can
// then attach that file when reporting a bug instead of having to
// reproduce it in front of a developer.
//
// The console passthrough always happens regardless of the configured
// level (DevTools shows everything); the configured minimum level (see
// `refreshLogLevel`/`getLogLevel`/`setLogLevel` below) only gates whether a
// given call also gets forwarded to the file.
//
// This is best-effort telemetry, not a critical path: every write is
// fire-and-forget (no await, errors swallowed) so a broken log pipe can
// never itself cause a visible failure, and several guards keep it from
// spamming the log file or recursing into itself.

import { invoke } from "@tauri-apps/api/core";
import { getLogLevel as getStoredLogLevel, setLogLevel as setStoredLogLevel, type LogLevel } from "./db/repositories/settingsRepo";

const DEDUPE_WINDOW_MS = 5000;
const MAX_WRITES_PER_MINUTE = 20;
const RATE_WINDOW_MS = 60_000;
const MAX_MESSAGE_LEN = 2000;

// Ascending severity. The configured minimum level gates which lines get
// forwarded to `append_log`/app.log — the console passthrough happens
// unconditionally regardless of this cache, so DevTools always shows
// everything.
const LEVEL_RANK: Record<LogLevel, number> = { debug: 0, info: 1, warn: 2, error: 3 };
const DEFAULT_LOG_LEVEL: LogLevel = "info";

// In-memory cache of the configured minimum level, so we don't hit the DB
// on every single log call. Populated by `refreshLogLevel()`, which should
// be called once at startup and again whenever the level is changed via
// Settings.
let cachedLogLevel: LogLevel = DEFAULT_LOG_LEVEL;

/** Re-reads the configured log level from settings and updates the
 *  in-memory cache used to gate file writes. Call once at startup
 *  (alongside `initErrorLogging()`) and again whenever the level is
 *  changed via the Settings UI so the change takes effect immediately. */
export async function refreshLogLevel(): Promise<void> {
  try {
    const level = await getStoredLogLevel();
    cachedLogLevel = level ?? DEFAULT_LOG_LEVEL;
  } catch {
    // Best-effort: keep whatever was cached before (or the default) if the
    // setting can't be read.
  }
}

/** Reads the current in-memory cached log level (does not hit the DB). */
export function getLogLevel(): LogLevel {
  return cachedLogLevel;
}

/** Persists a new minimum log level and immediately refreshes the
 *  in-memory cache so the change takes effect without a restart. */
export async function setLogLevel(level: LogLevel): Promise<void> {
  await setStoredLogLevel(level);
  await refreshLogLevel();
}

let installed = false;
// Recursion guard: set for the duration of a single append_log call so an
// error thrown while logging (e.g. from JSON.stringify or invoke itself)
// never triggers another log write.
let logging = false;

// message -> last-logged timestamp, for the 1-per-5s dedupe.
const lastSeen = new Map<string, number>();
// Timestamps (ms) of writes within the current rate-limit window.
let writeTimestamps: number[] = [];

function serializeArg(arg: unknown): string {
  if (arg instanceof Error) {
    const stackLines = (arg.stack ?? "").split("\n").slice(0, 3).join("\n");
    return `${arg.message}${stackLines ? `\n${stackLines}` : ""}`;
  }
  if (typeof arg === "string") return arg;
  try {
    return JSON.stringify(arg);
  } catch {
    return String(arg);
  }
}

function buildLine(level: string, args: unknown[]): string {
  const message = args.map(serializeArg).join(" ").slice(0, MAX_MESSAGE_LEN);
  return `${new Date().toISOString()} [${level}] ${message}`;
}

function shouldSkip(dedupeKey: string): boolean {
  const now = Date.now();

  const last = lastSeen.get(dedupeKey);
  if (last !== undefined && now - last < DEDUPE_WINDOW_MS) {
    return true;
  }
  lastSeen.set(dedupeKey, now);

  writeTimestamps = writeTimestamps.filter((ts) => now - ts < RATE_WINDOW_MS);
  if (writeTimestamps.length >= MAX_WRITES_PER_MINUTE) {
    return true;
  }
  writeTimestamps.push(now);
  return false;
}

function logLine(level: LogLevel, line: string) {
  if (logging) return; // recursion guard
  if (LEVEL_RANK[level] < LEVEL_RANK[cachedLogLevel]) return; // below configured threshold
  if (shouldSkip(line)) return;

  logging = true;
  try {
    // Fire-and-forget: never await, never let a rejection surface.
    void invoke("append_log", { line }).catch(() => {});
  } catch {
    // Swallow synchronous throws too (e.g. invoke not available outside Tauri).
  } finally {
    logging = false;
  }
}

/**
 * Installs the console/window hooks. Idempotent — safe to call more than
 * once (e.g. in tests or HMR) without double-wrapping console methods.
 */
export function initErrorLogging(): void {
  if (installed) return;
  installed = true;

  const originalError = console.error.bind(console);
  const originalWarn = console.warn.bind(console);
  const originalInfo = console.info.bind(console);
  const originalDebug = console.debug.bind(console);

  console.error = (...args: unknown[]) => {
    originalError(...args);
    logLine("error", buildLine("error", args));
  };

  console.warn = (...args: unknown[]) => {
    originalWarn(...args);
    logLine("warn", buildLine("warn", args));
  };

  // console.info is for deliberate, low-volume diagnostic breadcrumbs a
  // user might want to review later (e.g. the function-calling prototype's
  // round-trip log) — unlike error/warn it's opt-in per call site, so it's
  // wrapped the same way but expected to be used sparingly.
  console.info = (...args: unknown[]) => {
    originalInfo(...args);
    logLine("info", buildLine("info", args));
  };

  // console.debug is for verbose, only-useful-when-actively-debugging
  // breadcrumbs — gated out of app.log by default (min level "info") but
  // always visible in DevTools like the others.
  console.debug = (...args: unknown[]) => {
    originalDebug(...args);
    logLine("debug", buildLine("debug", args));
  };

  window.addEventListener("error", (event: ErrorEvent) => {
    const arg = event.error instanceof Error ? event.error : event.message;
    logLine("error", buildLine("error", [arg]));
  });

  window.addEventListener("unhandledrejection", (event: PromiseRejectionEvent) => {
    logLine("error", buildLine("error", [event.reason]));
  });
}

import i18n from "i18next";
import { initReactI18next } from "react-i18next";

import cs from "./cs.json";
import en from "./en.json";

export const namespaces = [
  "common",
  "chat",
  "characters",
  "personas",
  "lorebooks",
  "memory",
  "settings",
] as const;

export const supportedLanguages = ["cs", "en"] as const;
export type SupportedLanguage = (typeof supportedLanguages)[number];

void i18n.use(initReactI18next).init({
  resources: { cs, en },
  ns: namespaces,
  defaultNS: "common",
  lng: "cs",
  fallbackLng: "cs",
  interpolation: { escapeValue: false },
});

export default i18n;

import { create } from "zustand";

interface UndoAction {
  /** What was deleted (e.g. "Chat: My Adventure") */
  label: string;
  /** Async callback to restore the deleted item */
  onUndo: () => Promise<void>;
}

interface UndoState {
  /** Currently pending undo action, or null */
  pending: UndoAction | null;
  /** Timer id for auto-dismiss */
  timerId: ReturnType<typeof setTimeout> | null;
  /** Show an undo toast */
  show: (action: UndoAction) => void;
  /** Execute undo and clear the toast */
  undo: () => Promise<void>;
  /** Dismiss the toast without undoing */
  dismiss: () => void;
}

const TOAST_DURATION_MS = 5000;

export const useUndoStore = create<UndoState>((set, get) => ({
  pending: null,
  timerId: null,
  show: (action) => {
    const prev = get().timerId;
    if (prev) clearTimeout(prev);
    const timerId = setTimeout(() => {
      set({ pending: null, timerId: null });
    }, TOAST_DURATION_MS);
    set({ pending: action, timerId });
  },
  undo: async () => {
    const { pending, timerId } = get();
    if (timerId) clearTimeout(timerId);
    set({ pending: null, timerId: null });
    if (pending) {
      try {
        await pending.onUndo();
      } catch {
        // Undo failed — not much we can do at the toast level
      }
    }
  },
  dismiss: () => {
    const { timerId } = get();
    if (timerId) clearTimeout(timerId);
    set({ pending: null, timerId: null });
  },
}));

/** Hook that returns a show-undo helper for a given i18n label and undo callback. */
export function useUndoToast() {
  const { show } = useUndoStore();
  return {
    /** Call after deleting an entity — shows the undo toast. */
    toastUndo: (label: string, onUndo: () => Promise<void>) => {
      show({ label, onUndo });
    },
  };
}

import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";

import { checkForUpdate, relaunchApp, type AvailableUpdate } from "../platform";

type Phase = "idle" | "available" | "downloading" | "error";

/**
 * Non-intrusive update notification (M32). Checks GitHub Releases once on
 * startup; when a newer version exists, shows a small toast with an
 * "update now" button. Download + install + signature verification is
 * handled by tauri-plugin-updater; we just relaunch afterwards.
 */
export function UpdateBanner() {
  const { t } = useTranslation();
  const [update, setUpdate] = useState<AvailableUpdate | null>(null);
  const [phase, setPhase] = useState<Phase>("idle");
  const [dismissed, setDismissed] = useState(false);

  useEffect(() => {
    void checkForUpdate().then((u) => {
      if (u) {
        setUpdate(u);
        setPhase("available");
      }
    });
  }, []);

  if (!update || dismissed || phase === "idle") return null;

  const install = async () => {
    setPhase("downloading");
    try {
      await update.downloadAndInstall();
      await relaunchApp();
    } catch (err) {
      console.warn("update failed:", err);
      setPhase("error");
    }
  };

  return (
    <div
      className="fixed bottom-4 right-4 z-50 flex items-center gap-3 rounded-lg px-4 py-3 shadow-lg"
      style={{
        background: "var(--color-surface)",
        border: "1px solid var(--color-border)",
        color: "var(--color-text)",
      }}
    >
      <span className="text-sm">
        {phase === "error"
          ? t("update.error")
          : phase === "downloading"
            ? t("update.downloading")
            : t("update.available", { version: update.version })}
      </span>
      {phase === "available" && (
        <button
          type="button"
          className="rounded px-3 py-1 text-sm font-medium"
          style={{ background: "var(--color-accent)", color: "var(--color-accent-contrast, #fff)" }}
          onClick={() => void install()}
        >
          {t("update.installNow")}
        </button>
      )}
      {phase !== "downloading" && (
        <button
          type="button"
          className="text-sm"
          style={{ color: "var(--color-text-muted)" }}
          onClick={() => setDismissed(true)}
          aria-label={t("update.dismiss")}
        >
          ✕
        </button>
      )}
    </div>
  );
}

import { useTranslation } from "react-i18next";
import { useUndoStore } from "../useUndoToast";

export function UndoToast() {
  const { t } = useTranslation("common");
  const { pending, undo, dismiss } = useUndoStore();

  if (!pending) return null;

  return (
    <div
      className="fixed bottom-6 left-1/2 z-50 -translate-x-1/2 rounded-[var(--radius-md)] border px-4 py-2.5 text-sm shadow-lg"
      style={{
        borderColor: "var(--color-border-strong)",
        backgroundColor: "var(--color-bg-elevated)",
        color: "var(--color-text)",
        boxShadow: "var(--shadow-panel)",
      }}
      role="status"
      aria-live="polite"
    >
      <span className="mr-3">{pending.label}</span>
      <button
        type="button"
        onClick={() => void undo()}
        className="font-medium underline"
        style={{ color: "var(--color-accent)" }}
      >
        {t("undo")}
      </button>
      <button
        type="button"
        onClick={dismiss}
        className="ml-2 opacity-60 hover:opacity-100"
        aria-label={t("actions.close")}
      >
        ✕
      </button>
    </div>
  );
}

